from functools import lru_cache
from sympy import primefactors, integer_log
def A008479(n):
    if n == 1: return 1
    ps = tuple(sorted(primefactors(n)))
    @lru_cache(maxsize=None)
    def g(x,m): return 0 if x == 1 else sum(g(x//ps[m]**i,m-1) for i in range(1,integer_log(x,ps[m])[0]+1)) if m else integer_log(x,ps[0])[0]
    return g(n,len(ps)-1) # _Chai Wah Wu_, Apr 04 2026

